"use strict";(self.webpackChunkdst_api_webdocs=self.webpackChunkdst_api_webdocs||[]).push([[214132],{238360:e=>{e.exports=JSON.parse('{"tag":{"label":"timer","permalink":"/dst-api-webdocs/docs/tags/timer","allTagsPath":"/dst-api-webdocs/docs/tags","count":18,"items":[{"id":"game-scripts/components/beargerspawner","title":"Beargerspawner","description":"Manages spawning and timers for Bearger events in DST, tracking players, seasonal logic, and countdown warnings.","permalink":"/dst-api-webdocs/docs/game-scripts/components/beargerspawner"},{"id":"game-scripts/components/compostingbin","title":"Compostingbin","description":"Manages composting progress and material storage for composting bins, calculating processing time based on green-to-brown material ratios.","permalink":"/dst-api-webdocs/docs/game-scripts/components/compostingbin"},{"id":"game-scripts/components/decay","title":"Decay","description":"Manages a consumable fuel meter that decays over time and triggers events when fuel is spent or added.","permalink":"/dst-api-webdocs/docs/game-scripts/components/decay"},{"id":"game-scripts/prefabs/flower_cave","title":"Flower Cave","description":"Manages a light-emitting, harvestable cave plant that cycles between active, recharging, and idle states based on environmental light levels.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/flower_cave"},{"id":"game-scripts/prefabs/grass","title":"Grass","description":"Handles the lifecycle of grass patches including growth cycles, morphing into grass geckos, and interaction with world settings timers.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/grass"},{"id":"game-scripts/components/gym","title":"Gym","description":"Manages training interactions with a trainee entity, including training timer management, perishability checks, music state transitions, and phase-based rest behavior.","permalink":"/dst-api-webdocs/docs/game-scripts/components/gym"},{"id":"game-scripts/prefabs/monkey","title":"Monkey","description":"Manages the behavior, state, and lifecycle of the monkey entity, including transformations between normal and nightmare states based on world conditions and external triggers.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/monkey"},{"id":"game-scripts/prefabs/moonstorm_glass","title":"Moonstorm Glass","description":"A destructible, timed explosive structure that detonates after a fixed interval or when fully worked; inflicts area-of-effect damage to nearby entities and drops infused moon glass loot.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/moonstorm_glass"},{"id":"game-scripts/prefabs/planted_tree","title":"Planted Tree","description":"Provides shared logic and factory functions for sapling prefabs that grow into trees after a timed period, with support for digging to harvest early.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/planted_tree"},{"id":"game-scripts/prefabs/rift_terraformer","title":"Rift Terraformer","description":"Manages tile-level world transformation and reversion in the Rift biome, coordinating visual effects and sound synchronization over time.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/rift_terraformer"},{"id":"game-scripts/widgets/ringmeter","title":"RingMeter","description":"Displays a circular progress meter on-screen, typically used to indicate time-based events such as buff durations or cooldowns, with support for fading and flashing animations.","permalink":"/dst-api-webdocs/docs/game-scripts/widgets/ringmeter"},{"id":"game-scripts/prefabs/shadow_pillar","title":"Shadow Pillar","description":"Manages the lifecycle, visual FX, and timer-based behavior of shadow pillar entities that immobilize and deal damage to targets over time.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/shadow_pillar"},{"id":"game-scripts/components/stewer","title":"Stewer","description":"Manages cooking and spoilage timers for stew pot entities, handling cooking progression, product generation, and spoilage logic.","permalink":"/dst-api-webdocs/docs/game-scripts/components/stewer"},{"id":"game-scripts/components/timer","title":"Timer","description":"Manages named timers attached to an entity, supporting start, stop, pause, resume, and save/load operations.","permalink":"/dst-api-webdocs/docs/game-scripts/components/timer"},{"id":"game-scripts/components/tributable","title":"Tributable","description":"Manages tribute accumulation, reward thresholds, and decay timing for entities capable of receiving or dispensing offerings.","permalink":"/dst-api-webdocs/docs/game-scripts/components/tributable"},{"id":"game-scripts/components/vase","title":"Vase","description":"Manages flower placement, wilting behavior, and dynamic lighting for decorative vases in the game.","permalink":"/dst-api-webdocs/docs/game-scripts/components/vase"},{"id":"game-scripts/prefabs/waterplant_pollen","title":"Waterplant Pollen","description":"Manages the visual and gameplay effects of waterplant pollen clouds, including spawning fish attractants (chum pieces) over time and fading out after dispersal.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/waterplant_pollen"},{"id":"game-scripts/components/worldsettingstimer","title":"Worldsettingstimer","description":"Manages named, resumable, and persistent timers for world-scale settings or events.","permalink":"/dst-api-webdocs/docs/game-scripts/components/worldsettingstimer"}],"unlisted":false}}')}}]);